-- 170-sync-product-seo-meta.sql
--
-- Sync product SEO meta (meta_title, meta_description, meta_keyword) at
-- default scope (store_id=0) from the local source-of-truth into production.
--
-- Background: newer WSQ courses (TGS-*) on production were created via the
-- custom "Edit Course" dashboard, which did not persist the three SEO meta
-- fields back to EAV. Local has them. Live storefront falls back to short
-- description / site-wide keywords, hurting SERP and SEO compliance.
--
-- Strategy: fill-only. For every product with a non-empty scope-0 meta
-- value in local, INSERT ... ON DUPLICATE KEY UPDATE value =
-- IF(value IS NULL OR value='', VALUES(value), value).
--
-- - Adds the row if production doesn't have one.
-- - Fills the row if production has it but it's NULL / empty.
-- - LEAVES production's value alone if it's already non-empty.
--
-- Values are UNHEX('...') encoded to keep each statement on a single line
-- (apply.php splits on semicolon-at-end-of-line — multi-line values would
-- break that, see memory feedback_apply_php_sql_splitter.md /
-- feedback_migration_generator_skipped_strip.md).
--
-- Idempotent: re-running this against local or production is a no-op for
-- any row that already matches.
--
-- Per-store overrides (store_id=1 SG, store_id=2 MY) intentionally NOT
-- synced here — those need editorial review (e.g. course 1114's MY override
-- is a stale "Python 3" string, wrong product). Separate migration if needed.

